import parse_date from "stdlib/datetime"

fn parse_dates(text: Text) -> [Text, Text] {
    dates = split(text, ", ")
    return [dates[0], dates[1]]
}

fn date_diff(date1: Text, date2: Text) -> Number {
    date1 = to_date(date1)
    date2 = to_date(date2)
    return (date2 - date1).days
}

intent is_timeline_reasonable(dates: [Text, Text]) -> Text {
    goal: suggest timeline reasonableness

    # Parse dates
    meeting_date, deadline_date = parse_dates(dates[0])

    # Calculate days between them
    days_between = date_diff(meeting_date, deadline_date)

    # Suggest if the timeline is reasonable (<= 30 days)
    if days_between <= 30 {
        return "The timeline seems reasonable."
    } else {
        return "The timeline might be a bit tight. Consider adjusting it to allow for more time."
    }
}

entry main(text: Text) {
    dates = parse_dates(text)
    return is_timeline_reasonable(dates)
}
